import type { Metadata } from "next";
import JournalEditor from "./JournalEditor";

export const metadata: Metadata = {
  title: "仕訳入力（振替伝票） | ぐんじょう会計",
  description:
    "複式簿記の仕訳入力（振替伝票）画面。借方・貸方の勘定科目と金額を明細ごとに入力し、勘定科目マスタからの検索選択、税区分（課税10% / 軽減8% / 非課税 / 不課税 / 対象外）、借方合計と貸方合計の貸借一致チェックに対応。一致したときのみ登録できます。",
};

export default function JournalPage() {
  return <JournalEditor />;
}

// Domain model + helpers for the 仕訳入力 / 振替伝票 (double-entry journal) screen.
// Pure data + math, no React, so it can be unit-reasoned about in isolation.

/** 勘定科目の区分 (account classification). */
export type AccountCategory = "資産" | "負債" | "純資産" | "収益" | "費用";

export interface Account {
  /** 勘定科目コード (account code). */
  code: string;
  name: string;
  category: AccountCategory;
}

/** 勘定科目マスタ (chart of accounts) — a representative subset. */
export const ACCOUNT_MASTER: Account[] = [
  // 資産
  { code: "100", name: "現金", category: "資産" },
  { code: "110", name: "普通預金", category: "資産" },
  { code: "111", name: "当座預金", category: "資産" },
  { code: "135", name: "売掛金", category: "資産" },
  { code: "140", name: "未収入金", category: "資産" },
  { code: "150", name: "仮払金", category: "資産" },
  { code: "160", name: "仮払消費税", category: "資産" },
  { code: "170", name: "前払費用", category: "資産" },
  { code: "180", name: "備品", category: "資産" },
  // 負債
  { code: "300", name: "買掛金", category: "負債" },
  { code: "305", name: "未払金", category: "負債" },
  { code: "310", name: "未払費用", category: "負債" },
  { code: "320", name: "預り金", category: "負債" },
  { code: "330", name: "仮受消費税", category: "負債" },
  { code: "340", name: "短期借入金", category: "負債" },
  // 純資産
  { code: "500", name: "資本金", category: "純資産" },
  { code: "520", name: "繰越利益剰余金", category: "純資産" },
  // 収益
  { code: "600", name: "売上高", category: "収益" },
  { code: "610", name: "受取利息", category: "収益" },
  { code: "620", name: "雑収入", category: "収益" },
  // 費用
  { code: "700", name: "仕入高", category: "費用" },
  { code: "710", name: "旅費交通費", category: "費用" },
  { code: "715", name: "消耗品費", category: "費用" },
  { code: "720", name: "通信費", category: "費用" },
  { code: "725", name: "接待交際費", category: "費用" },
  { code: "730", name: "会議費", category: "費用" },
  { code: "735", name: "地代家賃", category: "費用" },
  { code: "740", name: "水道光熱費", category: "費用" },
  { code: "745", name: "支払手数料", category: "費用" },
  { code: "750", name: "新聞図書費", category: "費用" },
  { code: "760", name: "雑費", category: "費用" },
];

const CATEGORY_ORDER: AccountCategory[] = ["資産", "負債", "純資産", "収益", "費用"];

/**
 * Combobox options for the account picker. @gunjo/ui's `Combobox` takes a FLAT
 * `options[]` with no grouping, so we encode 区分 into the label (`[資産] 現金`)
 * and sort by 区分 → コード so same-category accounts cluster together. Search
 * matches the visible label, so typing a name or code still filters.
 */
// @gunjo/ui's Combobox feeds `option.value` to its internal cmdk filter, so the
// search matches the VALUE, not the label. If `value` were the bare code ("135"),
// typing a 科目名 ("売掛") would match nothing — useless for an account picker.
// So the option value is a searchable composite "コード 科目名 区分" ("135 売掛金 資産"),
// and we map code ↔ optionValue at the Combobox boundary (state still holds the code).
const SORTED_ACCOUNTS = [...ACCOUNT_MASTER].sort((a, b) => {
  const c = CATEGORY_ORDER.indexOf(a.category) - CATEGORY_ORDER.indexOf(b.category);
  return c !== 0 ? c : a.code.localeCompare(b.code);
});

export function optionValueForCode(code: string): string {
  const a = accountByCode(code);
  return a ? `${a.code} ${a.name} ${a.category}` : "";
}

export function codeFromOptionValue(optionValue: string): string {
  // Leading token is the code.
  return optionValue.split(" ")[0] ?? "";
}

export const ACCOUNT_OPTIONS = SORTED_ACCOUNTS.map((a) => ({
  value: `${a.code} ${a.name} ${a.category}`,
  label: `［${a.category}］${a.name}`,
}));

export function accountByCode(code: string): Account | undefined {
  return ACCOUNT_MASTER.find((a) => a.code === code);
}

/** Short display name for read-only contexts (e.g. recent-仕訳 list). */
export function accountDisplay(code: string): string {
  const a = accountByCode(code);
  return a ? a.name : "—";
}

// ----- 税区分 (tax category) -----

export type TaxCategoryId =
  | "taxable10"
  | "taxable8"
  | "taxfree" // 非課税
  | "nontax" // 不課税
  | "outofscope"; // 対象外

export interface TaxCategory {
  id: TaxCategoryId;
  label: string;
  /** Consumption-tax rate as a ratio. 0 for 非課税/不課税/対象外. */
  rate: number;
}

export const TAX_CATEGORIES: TaxCategory[] = [
  { id: "taxable10", label: "課税仕入 10%", rate: 0.1 },
  { id: "taxable8", label: "軽減 8%", rate: 0.08 },
  { id: "taxfree", label: "非課税", rate: 0 },
  { id: "nontax", label: "不課税", rate: 0 },
  { id: "outofscope", label: "対象外", rate: 0 },
];

export function taxCategoryById(id: TaxCategoryId): TaxCategory {
  return TAX_CATEGORIES.find((t) => t.id === id) ?? TAX_CATEGORIES[4];
}

// ----- 仕訳明細 (journal line) -----

export interface JournalLine {
  id: string;
  /** 借方勘定科目コード. "" = 未選択. */
  debitCode: string;
  /** 借方金額 (yen, integer). 0 / NaN = 未入力. */
  debitAmount: number;
  /** 貸方勘定科目コード. */
  creditCode: string;
  /** 貸方金額. */
  creditAmount: number;
  /** 税区分. */
  tax: TaxCategoryId;
  /** 行摘要 (per-line memo). */
  memo: string;
}

let rowSeq = 0;
export function createEmptyLine(): JournalLine {
  rowSeq += 1;
  return {
    id: `line-${Date.now().toString(36)}-${rowSeq}`,
    debitCode: "",
    debitAmount: 0,
    creditCode: "",
    creditAmount: 0,
    tax: "outofscope",
    memo: "",
  };
}

/** Seed entry: 旅費交通費 11,000 (税込) / 現金 11,000 — already balanced. */
export function seedLines(): JournalLine[] {
  rowSeq = 0;
  return [
    {
      id: "line-seed-1",
      debitCode: "710", // 旅費交通費
      debitAmount: 11000,
      creditCode: "100", // 現金
      creditAmount: 11000,
      tax: "taxable10",
      memo: "出張旅費（東京→大阪 新幹線）",
    },
    {
      id: "line-seed-2",
      debitCode: "715", // 消耗品費
      debitAmount: 5500,
      creditCode: "110", // 普通預金
      creditAmount: 5500,
      tax: "taxable10",
      memo: "文房具・コピー用紙",
    },
  ];
}

// ----- totals / balance -----

export interface JournalTotals {
  debitTotal: number;
  creditTotal: number;
  /** debitTotal − creditTotal. 0 = 貸借一致. */
  difference: number;
  balanced: boolean;
  /** Implied 仮払消費税 (purchase tax) from 税区分 on the debit side, by rate. */
  inputTax: number;
  /** Implied 仮受消費税 (sales tax) from 税区分 on the credit side, by rate. */
  outputTax: number;
}

/**
 * Tax-included amount → tax portion at the given ratio.
 * e.g. 11,000 @ 10% → 1,000. 0 if rate is 0. Rounded down (切り捨て), the JP default.
 */
export function taxFromGross(gross: number, rate: number): number {
  if (!rate || gross <= 0) return 0;
  // Round to a small epsilon before flooring so float artifacts (e.g.
  // 11000*0.1/1.1 = 999.9999…) don't drop a whole yen. Result is still 切り捨て.
  const exact = (gross * rate) / (1 + rate);
  return Math.floor(Math.round(exact * 1e6) / 1e6);
}

export function computeTotals(lines: JournalLine[]): JournalTotals {
  let debitTotal = 0;
  let creditTotal = 0;
  let inputTax = 0;
  let outputTax = 0;

  for (const l of lines) {
    const d = Number.isFinite(l.debitAmount) ? l.debitAmount : 0;
    const c = Number.isFinite(l.creditAmount) ? l.creditAmount : 0;
    debitTotal += d;
    creditTotal += c;
    const rate = taxCategoryById(l.tax).rate;
    // 借方に税区分の付いた費用/資産 → 仮払消費税。貸方に付けば 仮受消費税。
    if (rate > 0) {
      if (d > 0) inputTax += taxFromGross(d, rate);
      if (c > 0) outputTax += taxFromGross(c, rate);
    }
  }

  const difference = debitTotal - creditTotal;
  return {
    debitTotal,
    creditTotal,
    difference,
    balanced: difference === 0 && debitTotal > 0,
    inputTax,
    outputTax,
  };
}

// ----- validation -----

export interface LineError {
  /** Field-level reasons, for inline aria-invalid + the summary. */
  reasons: string[];
}

/** Per-line validation. A line must have a 借方 side and a 貸方 side, each with code+amount. */
export function validateLine(l: JournalLine): LineError {
  const reasons: string[] = [];
  const hasDebit = l.debitCode !== "" || l.debitAmount > 0;
  const hasCredit = l.creditCode !== "" || l.creditAmount > 0;

  if (hasDebit && l.debitCode === "") reasons.push("借方勘定科目が未選択です");
  if (hasDebit && l.debitAmount <= 0) reasons.push("借方金額を入力してください");
  if (hasCredit && l.creditCode === "") reasons.push("貸方勘定科目が未選択です");
  if (hasCredit && l.creditAmount <= 0) reasons.push("貸方金額を入力してください");
  if (!hasDebit && !hasCredit) reasons.push("借方または貸方を入力してください");
  return { reasons };
}

export function lineHasContent(l: JournalLine): boolean {
  return (
    l.debitCode !== "" ||
    l.creditCode !== "" ||
    l.debitAmount > 0 ||
    l.creditAmount > 0 ||
    l.memo.trim() !== ""
  );
}

"use client";

import * as React from "react";
import { ja } from "date-fns/locale/ja";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Button,
  Input,
  Textarea,
  DatePicker,
  Statistic,
  Badge,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormMessage,
  formatCurrency,
} from "@gunjo/ui";
import {
  IconCheck,
  IconAlertTriangle,
  IconScale,
  IconDeviceFloppy,
  IconEraser,
  IconReceipt,
} from "@tabler/icons-react";
import {
  type JournalLine,
  createEmptyLine,
  seedLines,
  computeTotals,
  validateLine,
  lineHasContent,
  accountDisplay,
  taxCategoryById,
} from "./journal-data";
import { JournalGrid } from "./JournalGrid";

type FlowState = "idle" | "draft" | "registered";

interface PostedEntry {
  voucherNo: string;
  date: string;
  summary: string;
  amount: number;
}

function todayDate(): Date {
  const d = new Date();
  d.setHours(0, 0, 0, 0);
  return d;
}

function formatDateJa(d: Date | undefined): string {
  if (!d) return "—";
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日`;
}

export default function JournalEditor() {
  // ---- 伝票ヘッダ ----
  const [date, setDate] = React.useState<Date | undefined>(todayDate());
  const [voucherNo, setVoucherNo] = React.useState("DEN-2026-0107");
  const [summary, setSummary] = React.useState("6月度 旅費・消耗品の精算");

  // ---- 仕訳明細 ----
  const [lines, setLines] = React.useState<JournalLine[]>(seedLines);

  // ---- 備考 ----
  const [note, setNote] = React.useState("");

  // ---- flow ----
  const [attempted, setAttempted] = React.useState(false);
  const [flow, setFlow] = React.useState<FlowState>("idle");
  const [posted, setPosted] = React.useState<PostedEntry[]>([]);
  const liveRef = React.useRef<HTMLParagraphElement>(null);

  const totals = React.useMemo(() => computeTotals(lines), [lines]);

  // ---- validation ----
  const lineErrorCount = React.useMemo(
    () => lines.filter((l) => validateLine(l).reasons.length > 0).length,
    [lines]
  );
  const filledLines = React.useMemo(() => lines.filter(lineHasContent), [lines]);

  const voucherNoError = !voucherNo.trim() ? "伝票番号を入力してください" : undefined;
  const dateError = !date ? "伝票日付を入力してください" : undefined;
  const emptyError =
    filledLines.length === 0 ? "仕訳明細を1行以上入力してください" : undefined;
  const lineError =
    lineErrorCount > 0 ? `未入力・未選択の項目がある明細が ${lineErrorCount} 件あります` : undefined;
  const balanceError = !totals.balanced
    ? totals.debitTotal === 0 && totals.creditTotal === 0
      ? "金額を入力してください"
      : `借方合計と貸方合計が一致していません（差額 ${formatCurrency(Math.abs(totals.difference))}）`
    : undefined;

  const blockingErrors = [dateError, voucherNoError, emptyError, lineError, balanceError].filter(
    Boolean
  ) as string[];
  const canRegister = blockingErrors.length === 0;

  // ---- handlers ----
  const announce = (msg: string) => {
    if (liveRef.current) liveRef.current.textContent = msg;
  };
  const touch = () => setFlow("idle");

  const handleLineChange = React.useCallback((id: string, patch: Partial<JournalLine>) => {
    setLines((prev) => prev.map((l) => (l.id === id ? { ...l, ...patch } : l)));
    setFlow("idle");
  }, []);
  const handleRemove = React.useCallback((id: string) => {
    setLines((prev) => (prev.length === 1 ? prev : prev.filter((l) => l.id !== id)));
    setFlow("idle");
  }, []);
  const handleAdd = React.useCallback(() => {
    setLines((prev) => [...prev, createEmptyLine()]);
    setFlow("idle");
  }, []);

  const handleRegister = () => {
    setAttempted(true);
    if (!canRegister) {
      announce(`登録できません。${blockingErrors.join("、")}`);
      return;
    }
    const entry: PostedEntry = {
      voucherNo,
      date: formatDateJa(date),
      summary: summary.trim() || "（摘要なし）",
      amount: totals.debitTotal,
    };
    setPosted((prev) => [entry, ...prev]);
    setFlow("registered");
    announce(
      `伝票 ${voucherNo} を登録しました。借方・貸方とも ${formatCurrency(totals.debitTotal)}、貸借一致。`
    );
  };

  const handleSaveDraft = () => {
    setFlow("draft");
    announce("下書きを保存しました。");
  };

  const handleClear = () => {
    setLines([createEmptyLine()]);
    setSummary("");
    setNote("");
    setVoucherNo("");
    setAttempted(false);
    setFlow("idle");
    announce("入力内容をクリアしました。");
  };

  const isRegistered = flow === "registered";

  // Balance banner content (always rendered, role/aria-live announces changes).
  const balanceVariant = totals.balanced ? "success" : "warning";

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-8 sm:px-6 lg:px-8">
      {/* Polite live region for status announcements */}
      <p ref={liveRef} role="status" aria-live="polite" className="sr-only" />

      <header className="mb-6 flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">仕訳入力（振替伝票）</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            借方・貸方の勘定科目と金額を入力します。借方合計と貸方合計が一致したときのみ登録できます。
          </p>
        </div>
        <Badge variant="info" className="w-fit">複式簿記</Badge>
      </header>

      {isRegistered && (
        <Alert variant="success" className="mb-6" role="status">
          <IconCheck className="h-4 w-4" aria-hidden />
          <AlertTitle as="h2">伝票を登録しました</AlertTitle>
          <AlertDescription>
            伝票番号 {voucherNo}（{formatDateJa(date)}）を登録しました。借方・貸方とも{" "}
            {formatCurrency(totals.debitTotal)}、貸借一致しています。
          </AlertDescription>
        </Alert>
      )}

      {attempted && !canRegister && (
        <Alert variant="destructive" className="mb-6" role="alert">
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
          <AlertTitle as="h2">登録できません</AlertTitle>
          <AlertDescription>
            <ul className="list-disc pl-5">
              {blockingErrors.map((e) => (
                <li key={e}>{e}</li>
              ))}
            </ul>
          </AlertDescription>
        </Alert>
      )}

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[1fr_300px]">
        {/* ===== Main column ===== */}
        <div className="flex min-w-0 flex-col gap-6">
          {/* --- 伝票ヘッダ --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">伝票情報</CardTitle>
              <CardDescription>振替伝票の日付・番号・摘要を入力します。</CardDescription>
            </CardHeader>
            <CardContent>
              <Form
                onSubmit={(e) => e.preventDefault()}
                className="grid grid-cols-1 gap-4 sm:grid-cols-2"
                aria-label="伝票情報"
              >
                <FormField error={attempted ? dateError : undefined} required className="p-0">
                  <FormLabel htmlFor="voucher-date">伝票日付</FormLabel>
                  <FormControl>
                    <DatePicker
                      id="voucher-date"
                      value={date}
                      onValueChange={(d) => {
                        setDate(d);
                        touch();
                      }}
                      locale={ja}
                    />
                  </FormControl>
                  <FormMessage />
                </FormField>

                <FormField error={attempted ? voucherNoError : undefined} required className="p-0">
                  <FormLabel>伝票番号</FormLabel>
                  <FormControl>
                    <Input
                      value={voucherNo}
                      onChange={(e) => {
                        setVoucherNo(e.target.value);
                        touch();
                      }}
                      placeholder="DEN-0000"
                    />
                  </FormControl>
                  <FormMessage />
                </FormField>

                <FormField className="p-0 sm:col-span-2">
                  <FormLabel>摘要（伝票全体）</FormLabel>
                  <FormControl>
                    <Input
                      value={summary}
                      onChange={(e) => {
                        setSummary(e.target.value);
                        touch();
                      }}
                      placeholder="例）6月度 旅費・消耗品の精算"
                    />
                  </FormControl>
                </FormField>
              </Form>
            </CardContent>
          </Card>

          {/* --- 仕訳明細 --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">仕訳明細</CardTitle>
              <CardDescription>
                各行に借方・貸方の勘定科目と金額、税区分、摘要を入力します。金額は税込で入力してください。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <JournalGrid
                lines={lines}
                totals={totals}
                onChange={handleLineChange}
                onRemove={handleRemove}
                onAdd={handleAdd}
                showErrors={attempted}
              />
            </CardContent>
          </Card>

          {/* --- 備考 --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">備考</CardTitle>
            </CardHeader>
            <CardContent>
              <Form onSubmit={(e) => e.preventDefault()}>
                <FormField className="p-0">
                  <FormLabel>備考（任意）</FormLabel>
                  <FormControl>
                    <Textarea
                      value={note}
                      onChange={(e) => setNote(e.target.value)}
                      rows={2}
                      placeholder="特記事項があれば入力してください"
                    />
                  </FormControl>
                </FormField>
              </Form>
            </CardContent>
          </Card>

          {/* --- 登録済みの仕訳 --- */}
          {posted.length > 0 && (
            <Card aria-labelledby="posted-heading">
              <CardHeader>
                <CardTitle as="h2" id="posted-heading">
                  登録済みの仕訳
                </CardTitle>
                <CardDescription>このセッションで登録した振替伝票です。</CardDescription>
              </CardHeader>
              <CardContent>
                <ul className="flex flex-col divide-y">
                  {posted.map((p, i) => (
                    <li
                      key={`${p.voucherNo}-${i}`}
                      className="flex items-center justify-between gap-3 py-2.5 first:pt-0 last:pb-0"
                    >
                      <div className="flex min-w-0 items-center gap-2">
                        <IconReceipt className="h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
                        <div className="min-w-0">
                          <p className="truncate text-sm font-medium">{p.summary}</p>
                          <p className="text-xs text-muted-foreground tabular-nums">
                            {p.voucherNo}・{p.date}
                          </p>
                        </div>
                      </div>
                      <span className="shrink-0 text-sm font-semibold tabular-nums">
                        {formatCurrency(p.amount)}
                      </span>
                    </li>
                  ))}
                </ul>
              </CardContent>
            </Card>
          )}
        </div>

        {/* ===== Balance + actions sidebar (sticky on desktop) ===== */}
        <aside className="lg:sticky lg:top-6 lg:self-start">
          <Card aria-labelledby="balance-heading">
            <CardHeader>
              <CardTitle as="h2" id="balance-heading">
                貸借バランス
              </CardTitle>
              <CardDescription>明細の変更に応じて自動で再計算されます。</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              {/* Stack the two totals: in the ~300px sidebar a 2-col grid crushes a
                  6-digit ¥ figure mid-digit (¥16,5 / 00). One column per total keeps
                  the whole amount on a line; tighter padding keeps it compact. */}
              <div className="grid grid-cols-1 gap-2 sm:grid-cols-2 lg:grid-cols-1">
                <Statistic
                  label="借方合計"
                  value={formatCurrency(totals.debitTotal)}
                  className="p-3"
                />
                <Statistic
                  label="貸方合計"
                  value={formatCurrency(totals.creditTotal)}
                  className="p-3"
                />
              </div>

              {/* Balance status — announced, conveyed by text + icon (not colour only). */}
              <Alert variant={balanceVariant} role="status" aria-live="polite">
                {totals.balanced ? (
                  <IconScale className="h-4 w-4" aria-hidden />
                ) : (
                  <IconAlertTriangle className="h-4 w-4" aria-hidden />
                )}
                <AlertTitle as="h3">
                  {totals.balanced ? "貸借一致" : "貸借不一致"}
                </AlertTitle>
                <AlertDescription>
                  {totals.balanced ? (
                    <>借方合計と貸方合計が一致しています。登録できます。</>
                  ) : (
                    <>
                      差額{" "}
                      <span className="font-semibold tabular-nums">
                        {formatCurrency(Math.abs(totals.difference))}
                      </span>
                      （
                      {totals.difference > 0 ? "借方が多い" : "貸方が多い"}）。
                      一致するまで登録できません。
                    </>
                  )}
                </AlertDescription>
              </Alert>

              <Separator />

              {/* 消費税アシスト — implied 仮払/仮受消費税 from 税区分 */}
              <div>
                <h3 className="mb-2 text-xs font-semibold text-muted-foreground">
                  消費税（税区分から自動計算）
                </h3>
                <dl className="space-y-2 text-sm">
                  <div className="flex items-center justify-between">
                    <dt className="text-muted-foreground">仮払消費税（借方）</dt>
                    <dd className="tabular-nums">{formatCurrency(totals.inputTax)}</dd>
                  </div>
                  <div className="flex items-center justify-between">
                    <dt className="text-muted-foreground">仮受消費税（貸方）</dt>
                    <dd className="tabular-nums">{formatCurrency(totals.outputTax)}</dd>
                  </div>
                </dl>
                <p className="mt-2 text-[11px] leading-relaxed text-muted-foreground">
                  税込金額と税区分から内税額を試算した参考値です（切り捨て）。
                </p>
              </div>

              <Separator />

              {/* Actions */}
              <div className="flex flex-col gap-2">
                <Button
                  type="button"
                  variant="primary"
                  onClick={handleRegister}
                  disabled={isRegistered}
                  aria-disabled={!canRegister || isRegistered}
                  aria-describedby={!canRegister ? "register-block-reason" : undefined}
                >
                  <IconCheck className="mr-1.5 h-4 w-4" aria-hidden />
                  {isRegistered ? "登録済み" : "登録する"}
                </Button>
                {!canRegister && !isRegistered && (
                  <p id="register-block-reason" className="text-xs text-muted-foreground">
                    {balanceError ?? blockingErrors[0]}（修正すると登録できます）
                  </p>
                )}
                <Button type="button" variant="secondary" onClick={handleSaveDraft}>
                  <IconDeviceFloppy className="mr-1.5 h-4 w-4" aria-hidden />
                  {flow === "draft" ? "下書きを保存しました" : "下書き保存"}
                </Button>
                <Button type="button" variant="outline" onClick={handleClear}>
                  <IconEraser className="mr-1.5 h-4 w-4" aria-hidden />
                  クリア
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Tiny legend: what the implied tax lines mean */}
          <p className="mt-3 px-1 text-[11px] leading-relaxed text-muted-foreground">
            借方に税区分が付いた行は仮払消費税、貸方に付いた行は仮受消費税として試算します。
            {totals.outputTax > 0 || totals.inputTax > 0 ? (
              <>
                {" "}
                例）{accountDisplay("710")}（{taxCategoryById("taxable10").label}）11,000円 → 仮払消費税 1,000円。
              </>
            ) : null}
          </p>
        </aside>
      </div>
    </main>
  );
}

"use client";

import * as React from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  TableFooter,
  Button,
  Input,
  Combobox,
  Select,
  EmptyState,
  formatCurrency,
} from "@gunjo/ui";
import { IconTrash, IconPlus, IconArrowsLeftRight } from "@tabler/icons-react";
import {
  type JournalLine,
  ACCOUNT_OPTIONS,
  optionValueForCode,
  codeFromOptionValue,
  TAX_CATEGORIES,
  type TaxCategoryId,
  validateLine,
  type JournalTotals,
} from "./journal-data";

export interface JournalGridProps {
  lines: JournalLine[];
  totals: JournalTotals;
  onChange: (id: string, patch: Partial<JournalLine>) => void;
  onRemove: (id: string) => void;
  onAdd: () => void;
  /** When true, surface per-line validation (after a register attempt). */
  showErrors: boolean;
}

/** Parse a yen text field → integer. Strips non-digits; "" → 0. */
function parseYen(v: string): number {
  const digits = v.replace(/[^\d]/g, "");
  return digits === "" ? 0 : Number(digits);
}

/**
 * Editable debit/credit journal grid.
 *
 * @gunjo/ui ships NO editable data-grid primitive (Table is a static <table>;
 * DataTable is read-only). So this is hand-rolled: desktop = a real <table> with
 * a per-cell control in every cell, mobile (<lg) = a stacked card per line so a
 * 7-column 借方/貸方 grid doesn't get crushed below ~1024px.
 *
 * ¥ amount cells use a plain <Input> (inputMode=numeric, digit-stripped,
 * right-aligned, tabular-nums) rather than <NumberInput> — NumberInput renders
 * `type=number` with spinner chevrons (noise + ~28px chrome for money) and can't
 * show grouped `11,000` while editing. We render the grouped figure read-only
 * under each total instead.
 */
export function JournalGrid({
  lines,
  totals,
  onChange,
  onRemove,
  onAdd,
  showErrors,
}: JournalGridProps) {
  if (lines.length === 0) {
    return (
      <div className="rounded-lg border border-dashed">
        <EmptyState
          icon={<IconArrowsLeftRight aria-hidden />}
          title="仕訳明細がありません"
          description="「行を追加」を押して、借方・貸方の勘定科目と金額を入力してください。"
          action={
            <Button type="button" variant="primary" onClick={onAdd}>
              <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
              行を追加
            </Button>
          }
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-3">
      {/* ===== Desktop / tablet: editable table (lg+) ===== */}
      <div className="hidden lg:block">
        <Table className="min-w-[920px]">
          <caption className="sr-only">
            仕訳明細。各行に借方（勘定科目・金額）と貸方（勘定科目・金額）、税区分、摘要を入力します。借方合計と貸方合計が一致したときのみ登録できます。
          </caption>
          <TableHeader>
            <TableRow>
              <TableHead scope="col" className="w-10 text-center">
                <span className="sr-only">行番号</span>#
              </TableHead>
              <TableHead scope="col" className="w-[17%]">借方 勘定科目</TableHead>
              <TableHead scope="col" className="w-[12%] text-right">借方 金額</TableHead>
              <TableHead scope="col" className="w-[17%]">貸方 勘定科目</TableHead>
              <TableHead scope="col" className="w-[12%] text-right">貸方 金額</TableHead>
              <TableHead scope="col" className="w-[12%]">税区分</TableHead>
              <TableHead scope="col" className="w-[18%]">摘要</TableHead>
              <TableHead scope="col" className="w-10 text-center">
                <span className="sr-only">操作</span>
              </TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {lines.map((line, index) => {
              const n = index + 1;
              const err = validateLine(line);
              const invalid = showErrors && err.reasons.length > 0;
              return (
                <TableRow
                  key={line.id}
                  className={invalid ? "bg-destructive-subtle/30" : undefined}
                >
                  <TableCell className="text-center align-middle text-xs font-medium text-muted-foreground tabular-nums">
                    {n}
                  </TableCell>
                  {/* 借方 勘定科目 */}
                  <TableCell>
                    <Combobox
                      aria-label={`${n}行目 借方勘定科目`}
                      options={ACCOUNT_OPTIONS}
                      value={optionValueForCode(line.debitCode)}
                      onValueChange={(v) => onChange(line.id, { debitCode: codeFromOptionValue(v) })}
                      placeholder="科目を選択"
                      searchPlaceholder="科目名・コードで検索…"
                      emptyMessage="該当する科目がありません"
                      aria-invalid={invalid && line.debitCode === "" && line.debitAmount > 0 ? true : undefined}
                      triggerClassName="h-9 text-sm"
                    />
                  </TableCell>
                  {/* 借方 金額 */}
                  <TableCell className="text-right">
                    <Input
                      aria-label={`${n}行目 借方金額`}
                      inputMode="numeric"
                      value={line.debitAmount > 0 ? String(line.debitAmount) : ""}
                      onChange={(e) => onChange(line.id, { debitAmount: parseYen(e.target.value) })}
                      placeholder="0"
                      aria-invalid={invalid && line.debitAmount <= 0 && line.debitCode !== "" ? true : undefined}
                      className="h-9 text-right tabular-nums"
                    />
                  </TableCell>
                  {/* 貸方 勘定科目 */}
                  <TableCell>
                    <Combobox
                      aria-label={`${n}行目 貸方勘定科目`}
                      options={ACCOUNT_OPTIONS}
                      value={optionValueForCode(line.creditCode)}
                      onValueChange={(v) => onChange(line.id, { creditCode: codeFromOptionValue(v) })}
                      placeholder="科目を選択"
                      searchPlaceholder="科目名・コードで検索…"
                      emptyMessage="該当する科目がありません"
                      aria-invalid={invalid && line.creditCode === "" && line.creditAmount > 0 ? true : undefined}
                      triggerClassName="h-9 text-sm"
                    />
                  </TableCell>
                  {/* 貸方 金額 */}
                  <TableCell className="text-right">
                    <Input
                      aria-label={`${n}行目 貸方金額`}
                      inputMode="numeric"
                      value={line.creditAmount > 0 ? String(line.creditAmount) : ""}
                      onChange={(e) => onChange(line.id, { creditAmount: parseYen(e.target.value) })}
                      placeholder="0"
                      aria-invalid={invalid && line.creditAmount <= 0 && line.creditCode !== "" ? true : undefined}
                      className="h-9 text-right tabular-nums"
                    />
                  </TableCell>
                  {/* 税区分 */}
                  <TableCell>
                    <Select
                      aria-label={`${n}行目 税区分`}
                      value={line.tax}
                      onChange={(e) => onChange(line.id, { tax: e.target.value as TaxCategoryId })}
                    >
                      {TAX_CATEGORIES.map((t) => (
                        <option key={t.id} value={t.id}>
                          {t.label}
                        </option>
                      ))}
                    </Select>
                  </TableCell>
                  {/* 摘要 */}
                  <TableCell>
                    <Input
                      aria-label={`${n}行目 摘要`}
                      value={line.memo}
                      onChange={(e) => onChange(line.id, { memo: e.target.value })}
                      placeholder="摘要"
                      className="h-9 text-sm"
                    />
                  </TableCell>
                  {/* 操作 */}
                  <TableCell className="text-center">
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => onRemove(line.id)}
                      aria-label={`${n}行目を削除`}
                      disabled={lines.length === 1}
                      className="text-muted-foreground hover:text-destructive"
                    >
                      <IconTrash className="h-4 w-4" aria-hidden />
                    </Button>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
          <TableFooter>
            <TableRow>
              <TableCell className="text-right text-xs font-semibold text-muted-foreground" colSpan={2}>
                合計
              </TableCell>
              <TableCell className="text-right font-semibold tabular-nums">
                {formatCurrency(totals.debitTotal)}
              </TableCell>
              <TableCell aria-hidden />
              <TableCell className="text-right font-semibold tabular-nums">
                {formatCurrency(totals.creditTotal)}
              </TableCell>
              <TableCell colSpan={3} aria-hidden />
            </TableRow>
          </TableFooter>
        </Table>
      </div>

      {/* ===== Mobile / narrow: stacked cards (<lg) ===== */}
      <ul className="flex flex-col gap-3 lg:hidden">
        {lines.map((line, index) => {
          const n = index + 1;
          const err = validateLine(line);
          const invalid = showErrors && err.reasons.length > 0;
          return (
            <li
              key={line.id}
              className={`rounded-lg border bg-card p-4 ${invalid ? "border-destructive-border" : ""}`}
            >
              <div className="mb-3 flex items-center justify-between">
                <span className="text-xs font-semibold text-muted-foreground">仕訳 {n}</span>
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  onClick={() => onRemove(line.id)}
                  aria-label={`${n}行目を削除`}
                  disabled={lines.length === 1}
                  className="h-8 w-8 text-muted-foreground hover:text-destructive"
                >
                  <IconTrash className="h-4 w-4" aria-hidden />
                </Button>
              </div>

              <div className="flex flex-col gap-4">
                {/* 借方 */}
                <fieldset className="rounded-md border border-border/70 bg-muted/20 p-3">
                  <legend className="px-1 text-xs font-semibold text-foreground">借方（左）</legend>
                  <div className="flex flex-col gap-2">
                    <label className="flex flex-col gap-1 text-xs font-medium">
                      勘定科目
                      <Combobox
                        aria-label={`${n}行目 借方勘定科目`}
                        options={ACCOUNT_OPTIONS}
                        value={optionValueForCode(line.debitCode)}
                        onValueChange={(v) => onChange(line.id, { debitCode: codeFromOptionValue(v) })}
                        placeholder="科目を選択"
                        searchPlaceholder="科目名・コードで検索…"
                        emptyMessage="該当する科目がありません"
                        aria-invalid={invalid && line.debitCode === "" && line.debitAmount > 0 ? true : undefined}
                      />
                    </label>
                    <label className="flex flex-col gap-1 text-xs font-medium">
                      金額（円）
                      <Input
                        aria-label={`${n}行目 借方金額`}
                        inputMode="numeric"
                        value={line.debitAmount > 0 ? String(line.debitAmount) : ""}
                        onChange={(e) => onChange(line.id, { debitAmount: parseYen(e.target.value) })}
                        placeholder="0"
                        aria-invalid={invalid && line.debitAmount <= 0 && line.debitCode !== "" ? true : undefined}
                        className="text-right tabular-nums"
                      />
                    </label>
                  </div>
                </fieldset>

                {/* 貸方 */}
                <fieldset className="rounded-md border border-border/70 bg-muted/20 p-3">
                  <legend className="px-1 text-xs font-semibold text-foreground">貸方（右）</legend>
                  <div className="flex flex-col gap-2">
                    <label className="flex flex-col gap-1 text-xs font-medium">
                      勘定科目
                      <Combobox
                        aria-label={`${n}行目 貸方勘定科目`}
                        options={ACCOUNT_OPTIONS}
                        value={optionValueForCode(line.creditCode)}
                        onValueChange={(v) => onChange(line.id, { creditCode: codeFromOptionValue(v) })}
                        placeholder="科目を選択"
                        searchPlaceholder="科目名・コードで検索…"
                        emptyMessage="該当する科目がありません"
                        aria-invalid={invalid && line.creditCode === "" && line.creditAmount > 0 ? true : undefined}
                      />
                    </label>
                    <label className="flex flex-col gap-1 text-xs font-medium">
                      金額（円）
                      <Input
                        aria-label={`${n}行目 貸方金額`}
                        inputMode="numeric"
                        value={line.creditAmount > 0 ? String(line.creditAmount) : ""}
                        onChange={(e) => onChange(line.id, { creditAmount: parseYen(e.target.value) })}
                        placeholder="0"
                        aria-invalid={invalid && line.creditAmount <= 0 && line.creditCode !== "" ? true : undefined}
                        className="text-right tabular-nums"
                      />
                    </label>
                  </div>
                </fieldset>

                <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
                  <label className="flex flex-col gap-1 text-xs font-medium">
                    税区分
                    <Select
                      aria-label={`${n}行目 税区分`}
                      value={line.tax}
                      onChange={(e) => onChange(line.id, { tax: e.target.value as TaxCategoryId })}
                    >
                      {TAX_CATEGORIES.map((t) => (
                        <option key={t.id} value={t.id}>
                          {t.label}
                        </option>
                      ))}
                    </Select>
                  </label>
                  <label className="flex flex-col gap-1 text-xs font-medium">
                    摘要
                    <Input
                      aria-label={`${n}行目 摘要`}
                      value={line.memo}
                      onChange={(e) => onChange(line.id, { memo: e.target.value })}
                      placeholder="摘要"
                    />
                  </label>
                </div>

                {invalid && (
                  <ul className="space-y-1" aria-live="polite">
                    {err.reasons.map((r) => (
                      <li key={r} className="text-xs font-medium text-destructive" role="alert">
                        {r}
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </li>
          );
        })}
      </ul>

      {/* Desktop per-row validation summary (associated by row number) */}
      {showErrors && lines.some((l) => validateLine(l).reasons.length > 0) && (
        <ul className="hidden space-y-1 lg:block" aria-live="polite">
          {lines.map((l, i) => {
            const reasons = validateLine(l).reasons;
            if (reasons.length === 0) return null;
            return (
              <li key={l.id} className="text-xs font-medium text-destructive" role="alert">
                {i + 1}行目：{reasons.join(" / ")}
              </li>
            );
          })}
        </ul>
      )}

      <div>
        <Button type="button" variant="outline" onClick={onAdd} className="w-full sm:w-auto">
          <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
          行を追加
        </Button>
      </div>
    </div>
  );
}
